class LUPrefix {
public:
    LUPrefix(int n) {
        uploaded = vector<bool>(n + 1, false);
    }

    void upload(int video) {
        uploaded[video] = true;
    }

    int longest() {
        int i = 1;
        while (i <= uploaded.size() && uploaded[i]) {
            i++;
        }
        return i - 1;
    }

private:
    vector<bool> uploaded;
};

